        recent = self.timeline[-10:]
        growth = np.mean([t.get('growth', 0) for t in recent])
        future = []
        for i in range(1, 11):
            future.append({
                'time': f'+{i} units',
                'projected': current_state.get('efficiency', 0) * (1 + growth) ** i,
                'confidence': max(0, 1 - i * 0.1)
            })
        self.future_projections = future
        return future

